const { cuboid, cylinder, union, subtract } = require('@jscad/modeling').primitives;
const { rotate, translate } = require('@jscad/modeling').transforms;

function main() {
  const base = cuboid({ size: [80, 80, 5] });
  const hingeMount = translate([0, 35, 10], cuboid({ size: [20, 10, 20] }));
  const arm = translate([0, 35, 20], rotate([Math.PI/4, 0, 0], cuboid({ size: [15, 5, 100], center: [0, 0, 50] })));
  return union(base, hingeMount, arm);
}

// Simplified gear representation
const { cylinder, union, subtract } = require('@jscad/modeling').primitives;
const { rotate, translate } = require('@jscad/modeling').transforms;

function main() {
  const hub = cylinder({ radius: 20, height: 5 });
  const teeth = [];
  for (let i = 0; i < 20; i++) {
    teeth.push(rotate([0, 0, (i * Math.PI * 2) / 20], translate([20, 0, 0], cuboid({ size: [4, 2, 5] }))));
  }
  const bore = cylinder({ radius: 2.5, height: 10 });
  return subtract(union(hub, ...teeth), bore);
}
